import{_ as a,c as o,o as d,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Histórico de Versões: Evolução de Recursos | opencode-agent-skills","description":"Aprenda sobre a evolução histórica das versões do plugin OpenCode Agent Skills. Este tutorial organiza todas as principais atualizações de recursos, correções de bugs, melhorias de arquitetura e notas sobre mudanças significativas da v0.1.0 à v0.6.4.","frontmatter":{"title":"Histórico de Versões: Evolução de Recursos | opencode-agent-skills","sidebarTitle":"O que há de novo","subtitle":"Histórico de Versões","description":"Aprenda sobre a evolução histórica das versões do plugin OpenCode Agent Skills. Este tutorial organiza todas as principais atualizações de recursos, correções de bugs, melhorias de arquitetura e notas sobre mudanças significativas da v0.1.0 à v0.6.4.","tags":["Atualizações de Versão","changelog","Histórico de Lançamentos"],"order":3},"headers":[],"relativePath":"pt/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"pt/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),r={name:"pt/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function i(s,e,l,n,c,u){return d(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="historico-de-versoes" tabindex="-1">Histórico de Versões <a class="header-anchor" href="#historico-de-versoes" aria-label="Permalink to &quot;Histórico de Versões&quot;">​</a></h1><p>Este documento registra todas as atualizações de versão do plugin OpenCode Agent Skills. Através do histórico de versões, você pode entender a trajetória de evolução dos recursos, problemas corrigidos e melhorias na arquitetura.</p><div class="tip custom-block"><p class="custom-block-title">Versão Atual</p><p>A versão estável mais recente é <strong>v0.6.4</strong> (2026-01-20)</p></div><h2 id="linha-do-tempo-de-versoes" tabindex="-1">Linha do Tempo de Versões <a class="header-anchor" href="#linha-do-tempo-de-versoes" aria-label="Permalink to &quot;Linha do Tempo de Versões&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Versão</th><th>Data de Lançamento</th><th>Tipo</th><th>Conteúdo Principal</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>Correção</td><td>Análise YAML, suporte Claude v2</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>Melhoria</td><td>Otimização de prompts de recomendação de skills</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>Correção</td><td>Separação de nomes de skills e nomes de diretórios</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>Melhoria</td><td>Evita recomendar skills já carregadas</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>Novo Recurso</td><td>Correspondência semântica, pré-cálculo de embeddings</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>Melhoria</td><td>Sugestões de correspondência fuzzy, refatoração</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>Melhoria</td><td>Simplificação do método de instalação</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>Melhoria</td><td>Busca recursiva de scripts</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>Correção</td><td>Tratamento de links simbólicos</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>Correção</td><td>Preservação do modo agente</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>Correção</td><td>Problema de troca de modelo</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>Novo Recurso</td><td>Funcionalidade de lista de arquivos</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>Novo Recurso</td><td>Modo Superpowers</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>Inicial</td><td>4 ferramentas, descoberta em múltiplos locais</td></tr></tbody></table><h2 id="registro-detalhado-de-alteracoes" tabindex="-1">Registro Detalhado de Alterações <a class="header-anchor" href="#registro-detalhado-de-alteracoes" aria-label="Permalink to &quot;Registro Detalhado de Alterações&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>Correções</strong>:</p><ul><li>Corrigida a análise de frontmatter YAML multilinha para skills (suporte a sintaxe de blocos <code>|</code> e <code>&gt;</code>), substituindo o analisador personalizado pela biblioteca <code>yaml</code></li><li>Adicionado suporte ao formato Claude v2, onde <code>installed_plugins.json</code> agora usa array de instalações de plugins em vez de objeto único</li></ul><p><strong>Melhorias</strong>:</p><ul><li>A descoberta de cache do plugin Claude Code agora suporta a nova estrutura de diretórios aninhados (<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>)</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>Melhorias</strong>:</p><ul><li>Otimizados os prompts de avaliação de skills para evitar que o modelo envie mensagens do tipo &quot;nenhuma skill necessária&quot; para o usuário (o usuário não vê os prompts de avaliação ocultos)</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>Correções</strong>:</p><ul><li>A validação de skills agora permite que o nome do diretório seja diferente do <code>name</code> no frontmatter do SKILL.md. O <code>name</code> no frontmatter é o identificador canônico, o nome do diretório é apenas para organização. Isso está de acordo com a Anthropic Agent Skills Spec.</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>Melhorias</strong>:</p><ul><li>A recomendação dinâmica de skills agora rastreia skills já carregadas em cada sessão, evitando recomendar novamente skills já carregadas, reduzindo prompts redundantes e uso de contexto</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>Novos Recursos</strong>:</p><ul><li><strong>Correspondência Semântica de Skills</strong>: Após a injeção inicial da lista de skills, mensagens subsequentes usam embeddings locais para correspondência com descrições de skills</li><li>Nova dependência <code>@huggingface/transformers</code> para geração local de embeddings (versão quantizada all-MiniLM-L6-v2)</li><li>Quando uma mensagem corresponde a uma skill disponível, um prompt de avaliação de 3 etapas é injetado (EVALUATE → DECIDE → ACTIVATE), incentivando o carregamento da skill (inspirado no <a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">artigo de blog</a> de <a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a>)</li><li>Cache em disco de embeddings para correspondência de baixa latência (<code>~/.cache/opencode-agent-skills/</code>)</li><li>Limpeza de sessão no evento <code>session.deleted</code></li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>Novos Recursos</strong>:</p><ul><li>Adicionadas sugestões de correspondência fuzzy &quot;você quis dizer...&quot; em todas as ferramentas (<code>use_skill</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>get_available_skills</code>)</li></ul><p><strong>Melhorias</strong>:</p><ul><li><strong>Mudança Significativa</strong>: Ferramenta <code>find_skills</code> renomeada para <code>get_available_skills</code> com intenção mais clara</li><li><strong>Interno</strong>: Reorganização da base de código em módulos independentes (<code>claude.ts</code>, <code>skills.ts</code>, <code>tools.ts</code>, <code>utils.ts</code>, <code>superpowers.ts</code>), melhorando a manutenibilidade</li><li><strong>Interno</strong>: Melhoria da qualidade do código através da remoção de comentários gerados por IA e código desnecessário</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>Melhorias</strong>:</p><ul><li>O método de instalação agora usa pacote npm através da configuração OpenCode, em vez de git clone + link simbólico</li></ul><p><strong>Remoções</strong>:</p><ul><li>Removido <code>INSTALL.md</code> (não mais necessário após simplificação da instalação)</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>Melhorias</strong>:</p><ul><li>A descoberta de scripts agora busca recursivamente todo o diretório de skills (profundidade máxima 10), em vez de apenas o diretório raiz e subdiretório <code>scripts/</code></li><li>Scripts agora são identificados por caminho relativo (ex: <code>tools/build.sh</code>) em vez de nome base</li><li>Parâmetro <code>skill_name</code> renomeado para <code>skill</code> em <code>read_skill_file</code>, <code>run_skill_script</code> e <code>use_skill</code></li><li>Parâmetro <code>script_name</code> renomeado para <code>script</code> em <code>run_skill_script</code></li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>Correções</strong>:</p><ul><li>Corrigida a detecção de arquivos e diretórios para lidar corretamente com links simbólicos usando <code>fs.stat</code></li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>Correções</strong>:</p><ul><li>Preservado o modo agente ao injetar mensagens sintéticas no início da sessão</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>Correções</strong>:</p><ul><li>Corrigida a troca inesperada de modelo ao usar ferramentas de skills passando explicitamente o modelo atual na operação <code>noReply</code> (solução temporária para o problema #4475 do opencode)</li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>Novos Recursos</strong>:</p><ul><li>Adicionada funcionalidade de lista de arquivos na saída <code>use_skill</code></li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>Novos Recursos</strong>:</p><ul><li>Adicionado suporte ao modo Superpowers</li><li>Adicionadas declarações de publicação</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>Novos Recursos</strong>:</p><ul><li>Adicionada ferramenta <code>use_skill</code> para carregar conteúdo de skills no contexto</li><li>Adicionada ferramenta <code>read_skill_file</code> para ler arquivos de suporte no diretório de skills</li><li>Adicionada ferramenta <code>run_skill_script</code> para executar scripts do diretório de skills</li><li>Adicionada ferramenta <code>find_skills</code> para pesquisar e listar skills disponíveis</li><li>Adicionada descoberta de skills em múltiplos locais (nível de projeto, nível de usuário e locais compatíveis com Claude)</li><li>Adicionada validação de frontmatter conforme Anthropic Agent Skills Spec v1.0</li><li>Adicionada injeção automática de lista de skills no início da sessão e após compactação de contexto</li></ul><p><strong>Novos Contribuidores</strong>:</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (Mantenedor)</li></ul><h2 id="visao-geral-da-evolucao-de-recursos" tabindex="-1">Visão Geral da Evolução de Recursos <a class="header-anchor" href="#visao-geral-da-evolucao-de-recursos" aria-label="Permalink to &quot;Visão Geral da Evolução de Recursos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Recurso</th><th>Versão Introduzida</th><th>Caminho de Evolução</th></tr></thead><tbody><tr><td>4 Ferramentas Básicas</td><td>v0.1.0</td><td>v0.5.0 adiciona correspondência fuzzy</td></tr><tr><td>Descoberta de Skills em Múltiplos Locais</td><td>v0.1.0</td><td>v0.4.1 simplifica instalação, v0.6.4 suporta Claude v2</td></tr><tr><td>Injeção Automática de Contexto</td><td>v0.1.0</td><td>v0.3.0 adiciona lista de arquivos, v0.6.1 evita recomendações duplicadas</td></tr><tr><td>Modo Superpowers</td><td>v0.2.0</td><td>Estabilidade contínua</td></tr><tr><td>Busca Recursiva de Scripts</td><td>v0.4.0</td><td>v0.3.3 corrige links simbólicos</td></tr><tr><td>Correspondência Semântica</td><td>v0.6.0</td><td>v0.6.1 evita duplicação, v0.6.3 otimiza prompts</td></tr><tr><td>Sugestões de Correspondência Fuzzy</td><td>v0.5.0</td><td>Estabilidade contínua</td></tr></tbody></table><h2 id="notas-sobre-mudancas-significativas" tabindex="-1">Notas sobre Mudanças Significativas <a class="header-anchor" href="#notas-sobre-mudancas-significativas" aria-label="Permalink to &quot;Notas sobre Mudanças Significativas&quot;">​</a></h2><h3 id="v0-6-0-funcionalidade-de-correspondencia-semantica" tabindex="-1">v0.6.0: Funcionalidade de Correspondência Semântica <a class="header-anchor" href="#v0-6-0-funcionalidade-de-correspondencia-semantica" aria-label="Permalink to &quot;v0.6.0: Funcionalidade de Correspondência Semântica&quot;">​</a></h3><p>Introduzida capacidade de correspondência semântica baseada em embeddings locais, permitindo que a IA recomende automaticamente skills relevantes com base no conteúdo da mensagem do usuário, sem necessidade de memorizar manualmente os nomes das skills.</p><ul><li><strong>Detalhes Técnicos</strong>: Usa o modelo <code>all-MiniLM-L6-v2</code> da HuggingFace (versão quantizada q8)</li><li><strong>Mecanismo de Cache</strong>: Resultados de embedding são armazenados em cache em <code>~/.cache/opencode-agent-skills/</code>, melhorando a velocidade de correspondências subsequentes</li><li><strong>Fluxo de Correspondência</strong>: Mensagem do usuário → embedding → cálculo de similaridade de cosseno com descrições de skills → Top 5 recomendações (limiar 0,35)</li></ul><h3 id="v0-5-0-refatoracao-e-renomeacao-de-ferramentas" tabindex="-1">v0.5.0: Refatoração e Renomeação de Ferramentas <a class="header-anchor" href="#v0-5-0-refatoracao-e-renomeacao-de-ferramentas" aria-label="Permalink to &quot;v0.5.0: Refatoração e Renomeação de Ferramentas&quot;">​</a></h3><p>Reestruturação da arquitetura do código para design modular, com nomenclatura de ferramentas mais clara:</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-upgrade-do-mecanismo-de-descoberta-de-scripts" tabindex="-1">v0.4.0: Upgrade do Mecanismo de Descoberta de Scripts <a class="header-anchor" href="#v0-4-0-upgrade-do-mecanismo-de-descoberta-de-scripts" aria-label="Permalink to &quot;v0.4.0: Upgrade do Mecanismo de Descoberta de Scripts&quot;">​</a></h3><p>A descoberta de scripts evoluiu de &quot;apenas diretório raiz + scripts/&quot; para &quot;busca recursiva em todo o diretório de skills&quot; (profundidade máxima 10), suportando organizações de scripts mais flexíveis.</p><h3 id="v0-2-0-integracao-superpowers" tabindex="-1">v0.2.0: Integração Superpowers <a class="header-anchor" href="#v0-2-0-integracao-superpowers" aria-label="Permalink to &quot;v0.2.0: Integração Superpowers&quot;">​</a></h3><p>Adicionado suporte ao modo de fluxo de trabalho Superpowers, requerendo a instalação da skill <code>using-superpowers</code> e configuração da variável de ambiente <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>.</p><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Número da Linha</th></tr></thead><tbody><tr><td>Número da Versão Atual</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>Histórico de Versões</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>Informações de Versões Principais</strong>:</p><ul><li><code>v0.6.4</code>: Versão atual (2026-01-20)</li><li><code>v0.6.0</code>: Introdução da correspondência semântica (2025-12-12)</li><li><code>v0.5.0</code>: Versão refatorada (2025-12-11)</li><li><code>v0.1.0</code>: Versão inicial (2025-11-26)</li></ul></details>',72)])])}const h=a(r,[["render",i]]);export{m as __pageData,h as default};
